import Slider from "react-slick";
import "slick-carousel/slick/slick.css";
import "slick-carousel/slick/slick-theme.css";
import styled from "styled-components";

function Banner() {
  let settings = {
    dots: false,
    infinite: true,
    speed: 400,
    slidesToShow: 1,
    slidesToScroll: 1,
    autoplay: true,
  };

  return (
    <Carousel className="banner" {...settings}>
      <Wrap>
        <img src="/images/slides/slide1.jpg" alt="background" />
      </Wrap>
      <Wrap>
        <img src="/images/slides/slide2.jpg" alt="background" />
      </Wrap>
      <Wrap>
        <img src="/images/slides/slide3.jpg" alt="background" />
      </Wrap>
      <Wrap>
        <img src="/images/slides/slide4.jpg" alt="background" />
      </Wrap>
      <Wrap>
        <img src="/images/slides/slide5.jpg" alt="background" />
      </Wrap>
      <Wrap>
        <img
          src="https://image.tmdb.org/t/p/original//7CamWBejQ9JQOO5vAghZfrFpMXY.jpg"
          alt="background"
        />
      </Wrap>

      <Wrap>
        <img
          src="https://image.tmdb.org/t/p/original//dK12GIdhGP6NPGFssK2Fh265jyr.jpg"
          alt="background"
        />
      </Wrap>
      <Wrap>
        <img
          src="https://image.tmdb.org/t/p/original//iQFcwSGbZXMkeyKrxbPnwnRo5fl.jpg"
          alt="background"
        />
      </Wrap>
      <Wrap>
        <img
          src="https://image.tmdb.org/t/p/original//t7I942V5U1Ggn6OevN75u3sNYH9.jpg"
          alt="background"
        />
      </Wrap>
      <Wrap>
        <img
          src="https://image.tmdb.org/t/p/original//2hGjmgZrS1nlsEl5PZorn7EsmzH.jpg"
          alt="background"
        />
      </Wrap>
      <Wrap>
        <img
          src="https://image.tmdb.org/t/p/original//egoyMDLqCxzjnSrWOz50uLlJWmD.jpg"
          alt="background"
        />
      </Wrap>
      <Wrap>
        <img
          src="https://image.tmdb.org/t/p/original//tj4lzGgHrfjnjVqAKkLIjFqPSyO.jpg"
          alt="background"
        />
      </Wrap>
      <Wrap>
        <img
          src="https://image.tmdb.org/t/p/original//yzH5zvuEzzsHLZnn0jwYoPf0CMT.jpg"
          alt="background"
        />
      </Wrap>
    </Carousel>
  );
}

export default Banner;

const Carousel = styled(Slider)`
  color: #fff;
  object-fit: contain;
  position: relative;
  background: #111;
  mask-image: linear-gradient(to bottom, rgba(0, 0, 0, 15), rgba(0, 0, 0, 9));
  max-height: 500px;
  overflow-x: hidden;

  @media (max-width: 700px) {
    max-height: 200px;
  }

  ul li button {
    &:before {
      font-size: 10px;
      color: rgb(150, 158, 171);
    }
  }

  li.slick-active button:before {
    color: #fff;
  }

  button {
    z-index: 1;
  }
`;

const Wrap = styled.div`
  cursor: pointer;
  img {
    width: 100%;
    height: 100%;
    object-fit: cover;
  }
`;
